"""Juicy manual translations 301-400."""

T = {
301: {"nativeDefinition": "To establish or strengthen something firmly.", "japaneseMeaning": "（地位などを）確固たるものにする", "etymology": "cement（セメント）が比喩的に関係や地位を固めることを表す。", "examples": {"B": "この映画で彼は僕のお気に入りの俳優の一人としての地位を確固たるものにした。", "C": "金メダルを取ったことで、世界最高の野球チームとしての地位が確立されたと思う。", "D": "何かをしっかり確立する。"}},
302: {"nativeDefinition": "To encounter an unexpected problem or obstacle.", "japaneseMeaning": "（予期せぬ問題に）ぶつかる、つまずく", "etymology": "hit a snag（引っかかりにぶつかる）が障害に遭遇することを表す。", "examples": {"B": "車を数時間借りられる？予期せぬ問題があって、それで解決してもらいたい。", "C": "来週オーストラリアに行く予定だったけど、ビザ申請でつまずいた。", "D": "予期しない問題に遭遇する。"}},
303: {"nativeDefinition": "Deeply established and difficult to change.", "japaneseMeaning": "根深い、根強い", "etymology": "deep-rooted（深く根ざした）が長年の習慣や偏見を表す。", "examples": {"B": "女の子に好かれてるって言われても信じられない。根深い信頼問題があるから。", "C": "この国ではジェンダーバイアスがまだ根深い。ほとんどの場合無意識的だ。", "D": "深く根ざしている。"}},
304: {"nativeDefinition": "By itself; intrinsically (used to narrow or clarify meaning).", "japaneseMeaning": "それ自体は、厳密には", "etymology": "per se（それ自体で）がラテン語由来で本質的な意味を限定する。", "examples": {"B": "仕事そのものは嫌いじゃない。一緒に働く人たちのことが問題。", "C": "犬が嫌いというわけじゃない、per se。猫が本当に嫌いなだけ。", "D": "正確に。"}},
305: {"nativeDefinition": "Expressing regret about missed opportunities (would have, should have, could have).", "japaneseMeaning": "〜すればよかった、後悔の念", "etymology": "woulda shoulda coulda（〜したかった、すべきだった、できた）が後悔の口語表現。", "examples": {"B": "後悔の念でいっぱいだ。ビットコインにもっと投資しておけばよかった。", "C": "大学時代にお金を貯めておけばよかったのに、全部酒に使っちゃった。", "D": "後悔。"}},
306: {"nativeDefinition": "A long, complicated series of events.", "japaneseMeaning": "長い話、一大騒動", "etymology": "saga（サガ）が長く複雑な出来事の連続を表す。", "examples": {"B": "今朝の通勤は一大騒動だった。ランチで全部話すね。", "C": "家族全員でのクリスマスディナーはいつも一大騒動。総出でやっても、時間も手間もかかる。", "D": "長く複雑な話。"}},
307: {"nativeDefinition": "To become more confident and sociable.", "japaneseMeaning": "（殻から）出て、打ち解ける", "etymology": "come out of one's shell（殻から出る）が内向的な人が社交的になることを表す。", "examples": {"B": "昔はもっと内向的だったけど、バスケをやるようになって打ち解けた。", "C": "内向的なのが嫌で、今年の目標はもう少し殻から出て新しい人に会うこと。", "D": "もっと社交的になる。"}},
308: {"nativeDefinition": "To argue or worry about insignificant details.", "japaneseMeaning": "あら探しをする、細かいことにこだわる", "etymology": "split hairs（毛を割る）が些細な違いにこだわることを表す。", "examples": {"B": "悪魔は細部に宿るのはわかるけど、ロゴが1ピクセルずれてるって文句はあら探しじゃない？誰が気づくの？", "C": "政治家があら探しして、部屋の象（本題）に触れないのにイライラする。", "D": "小さな詳細にうるさすぎる。"}},
309: {"nativeDefinition": "Except for; not considering.", "japaneseMeaning": "〜は別として、〜を除けば", "etymology": "aside（脇に）が本題から除外することを表す。", "examples": {"B": "離婚の質問は別として、アンドリューは僕の質問にほぼ全部答えてくれる。いいスポーツマンだ。", "C": "守備は別として、ジョーは非常に知的な選手だ。", "D": "何かを除いて。"}},
310: {"nativeDefinition": "A situation where the outcome is essentially random.", "japaneseMeaning": "運次第、五分五分", "etymology": "coin flip（コイン投げ）が50%の確率を表す。", "examples": {"B": "来年東京と大阪どっちに住むかまだ決めてない。五分五分だ。", "C": "投資は長期で考えるべき。デイトレードや短期投資は運次第に近いと思う。", "D": "不確実な状況。"}},
311: {"nativeDefinition": "A hypothetical scenario used to explore ideas.", "japaneseMeaning": "思考実験", "etymology": "thought experiment（思考実験）が仮定の状況で考えることを表す。", "examples": {"B": "ちょっとした思考実験。1万ドルが20%の確率で当たるか、確実に1000ドルか？僕は前者を選ぶ。", "C": "無人島に3つ持っていくものは？面白い思考実験だよね。", "D": "仮説的な質問。"}},
312: {"nativeDefinition": "Directly and confrontationally.", "japaneseMeaning": "正面から、真っ向から", "etymology": "head-on（正面から）が直接取り組むことを表す。", "examples": {"B": "気候変動問題を解決するには、各国が協力して真っ向から取り組むしかない。", "C": "問題を避けると不安が増すから、絆創膏を一気に剥がして真っ向から向き合う方がいい。", "D": "直接。"}},
313: {"nativeDefinition": "To know someone well enough to call them by their first name.", "japaneseMeaning": "（名前で呼べるほど）親しい", "etymology": "on a first name basis（名前で呼ぶ関係）が親密さを表す。", "examples": {"B": "ちょっと待って、どうやって金正恩と名前で呼べるほど親しくなったの？スパイじゃないでしょ？", "C": "目標はアリアナ・グランデと名前で呼べるほど親しくなること。本気だよ。", "D": "誰かと親しい関係にある。"}},
314: {"nativeDefinition": "Still active and thriving.", "japaneseMeaning": "今も健在で、元気な", "etymology": "alive and kicking（生きて蹴っている）が健在であることを表す。", "examples": {"B": "人種差別は世界中で今も健在だ。ただ隠すのが上手くなっただけ。", "C": "うん、まだ存在するけど、健在と言うのは言い過ぎかも。", "D": "活発に存在する。"}},
315: {"nativeDefinition": "And similar things; and so on.", "japaneseMeaning": "などなど、〜とか", "etymology": "and whatnot（何とか）がその他諸々を表す口語。", "examples": {"B": "ラップトップがウイルスだらけで起動しない。もう寿命かも。", "C": "アドレナリンが好きなんだ。スカイダイビングとかバンジージャンプとか。", "D": "など。"}},
316: {"nativeDefinition": "As the proverb or saying goes.", "japaneseMeaning": "ことわざにあるように、言うように", "etymology": "as the saying goes（ことわざにあるように）が格言の引用を表す。", "examples": {"B": "まだ勝ってないのに、なんで既に祝ってる人がいるの？ことわざにあるように、孵る前に数えるな。", "C": "来年は南米をバックパックで旅する。ことわざにあるように、旅はお金を使っても豊かにしてくれる唯一のもの。", "D": "格言が言うように。"}},
317: {"nativeDefinition": "Even someone usually wrong can occasionally be right.", "japaneseMeaning": "たまには当たる、時計は二度正しい", "etymology": "壊れた時計も1日に2回は正しいということわざ。", "examples": {"B": "キャストの株価予測が今回は当たった。壊れた時計も1日に2回は正しいね。", "C": "彼の言うことはほとんどナンセンス。たまに筋が通ることもあるけど、壊れた時計も1日に2回は正しい。", "D": "普段信頼できない人や物でも、たまには正しいことがある。"}},
318: {"nativeDefinition": "Always late for everything.", "japaneseMeaning": "いつも遅刻する、時間にルーズ", "etymology": "be late for one's own funeral（自分の葬式に遅刻する）が極端な遅刻を表す。", "examples": {"B": "オーウェンはすごくうざい。いつも遅刻するけど、ずっと一緒にいてくれた。そんな友達は少ないから大切にしてる。", "C": "おい、ダンはどこ？あいつ、自分の葬式に遅刻しそうだよ。", "D": "時間にルーズである。"}},
319: {"nativeDefinition": "Exceptional; extraordinary.", "japaneseMeaning": "すごい、別格の", "etymology": "something else（何か他のもの）が並外れたことを表す口語。", "examples": {"B": "スターバックスのカスタマーサービスは本当に別格。いつもお客を笑顔にするために余計な努力をする。", "C": "たくさんヘッドホン試したけど、このボーズは本当に別格。コスパもすごい。", "D": "並外れている。"}},
320: {"nativeDefinition": "To earn money to support one's family.", "japaneseMeaning": "（家族の）生活費を稼ぐ", "etymology": "bring home the bacon（ベーコンを家に持ち帰る）が家計を支えることを表す。", "examples": {"B": "僕だけかもしれないけど、男には生活費を稼ぐプレッシャーがまだあると思う。", "C": "最近調子悪いけど、今夜全力を出せば勝てると信じてる。生活費を稼ぐために。", "D": "家計を支えるお金を稼ぐ。"}},
321: {"nativeDefinition": "To take a seat; sit down.", "japaneseMeaning": "（椅子を）引いて座る、座って", "etymology": "pull up a chair（椅子を引く）が着席を促す表現。", "examples": {"B": "みんな、椅子引いて座って。もうすぐディナーの準備できる。", "C": "椅子引いて座って、一緒に映画見よう。", "D": "座る。"}},
322: {"nativeDefinition": "Presenting only two mutually exclusive choices.", "japaneseMeaning": "二者択一の、どちらか一方", "etymology": "either-or（どちらか）が二択の状況を表す。", "examples": {"B": "キャリアを築くことと子育ては二者択一じゃない。両方できる方法はある。", "C": "勉強は質と量どっちを重視すべきかよく聞かれるけど、二者択一じゃないと思う。", "D": "二つの選択肢。"}},
323: {"nativeDefinition": "To become suddenly very popular.", "japaneseMeaning": "（〜を）席巻する、一気に流行る", "etymology": "take by storm（嵐のように襲う）が急速な流行を表す。", "examples": {"B": "あのPPAPがインターネットを席巻して、1年くらいで消えたの変だよね。", "C": "ポケモンGOは数年前に世界を席巻したけど、まだやってる人いる？僕はずっと前にアンインストールした。", "D": "突然とても人気になる。"}},
324: {"nativeDefinition": "To reveal a secret unintentionally or carelessly.", "japaneseMeaning": "（秘密を）漏らす、バラす", "etymology": "let the cat out of the bag（猫を袋から出す）が秘密を漏らすことを表す。", "examples": {"B": "カメのペットを妻に内緒にしようとしてたのに、グレッグが今日バラしちゃった。", "C": "個人的な意見だけど、辞めることを秘密にしたいならニーナに言っちゃダメ。絶対バラすよ。", "D": "秘密を明かす。"}},
325: {"nativeDefinition": "To stop a habitual behavior.", "japaneseMeaning": "（習慣を）やめる、断つ", "etymology": "break a habit（習慣を壊す）が悪習慣を断つことを表す。", "examples": {"B": "彼女と同棲する前に喫煙をやめたい。今しかない。", "C": "仕事後にポテチを食べる習慣を断ててない。良い点として、以前より水をたくさん飲むようになった。", "D": "何かをやめる。"}},
326: {"nativeDefinition": "To go out into public areas; to be released to the market.", "japaneseMeaning": "街に出る、（製品が）発売される", "etymology": "hit the streets（街を歩く）が一般公開や発売を表す。", "examples": {"B": "今日はニューヨークの街に出て、ニューヨーク生活の長所と短所を人々に聞く。", "C": "この新製品が街に出るのが待ち遠しい。", "D": "街を歩く。発売される。"}},
327: {"nativeDefinition": "To present or describe something in a particular way.", "japaneseMeaning": "（物事を）枠組みで捉える、言い方を変える", "etymology": "frame（枠）が物事の見せ方や捉え方を表す。", "examples": {"B": "どう枠組みで捉えるかによって、ギリギリ合格は運が良かったとも、ちょうどいい勉強量だったとも言える。", "C": "この国に人種差別はあるのはわかるけど、すべての問題を人種問題として枠組みで捉えるのはナンセンス。", "D": "何かを考慮する。"}},
328: {"nativeDefinition": "To stare at someone; to estimate roughly by sight.", "japaneseMeaning": "（人を）じろじろ見る、（目分量で）見積もる", "etymology": "eyeball（目玉）が凝視や目分量を表す。", "examples": {"B": "やばい、向かいの男がじろじろ見てくる。気持ち悪い。", "C": "レシピがなかったから目分量で調味料を入れたけど、ほぼ完璧だった。", "D": "じっと見る。目で大まかに測る。"}},
329: {"nativeDefinition": "A moment of sudden realization or inspiration.", "japaneseMeaning": "ひらめき、電球が点灯する瞬間", "etymology": "light-bulb moment（電球の瞬間）がアイデアが閃くことを表す。", "examples": {"B": "さっきシャワー中にひらめいたんだけど、もう何だったか忘れた。", "C": "ワークショップ中にひらめきがあって、自分の情熱はロボティクスとプログラミングにあるとわかった。", "D": "突然の気づきやインスピレーションの瞬間。"}},
330: {"nativeDefinition": "Areas of ambiguity; not simply black and white.", "japaneseMeaning": "グレーゾーン、曖昧な部分", "etymology": "shades of gray（灰色の色合い）が白黒ではない曖昧さを表す。", "examples": {"B": "言語は常に論理的じゃない。グレーゾーンがあることを受け入れないと、ずっとイライラするよ。", "C": "人生は白黒じゃなくグレーゾーン。だからほとんどの人はたどたどしく生きてる。", "D": "曖昧さ。"}},
331: {"nativeDefinition": "To suggest an idea to someone for their reaction.", "japaneseMeaning": "（アイデアを）ちょっと提案する、打診する", "etymology": "float an idea（アイデアを浮かべる）が試しに提案することを表す。", "examples": {"B": "このアイデアを提案してくれたのはフィオナだから、僕が考えたわけじゃない。", "C": "ちょっと耳を貸してくれる？アイデアを打診したいんだけど。", "D": "誰かにアイデアを提案する。"}},
332: {"nativeDefinition": "Something with both positive and negative consequences.", "japaneseMeaning": "諸刃の剣、両刃の剣", "etymology": "double-edged sword（両刃の剣）が一長一短を表す。", "examples": {"B": "自分の意見をはっきり言うべきだと思うけど、嫌われるかもしれない。諸刃の剣みたいなもの。", "C": "インターネットは諸刃の剣。夢を叶えるチャンスをくれるけど、裏を返せば競争も激化する。", "D": "プラスとマイナスの両面があるもの。"}},
333: {"nativeDefinition": "The situation is unfairly disadvantageous to someone.", "japaneseMeaning": "不利な状況だ、勝負が不公平", "etymology": "the deck is stacked（山札が積まれている）が不正に不利な状況を表す。", "examples": {"B": "要するに、勝負が不公平なんだ。今年どれだけ頑張っても昇進はない。", "C": "大学に行かないと就職で不利な状況になる。とはいえ不可能じゃないから、自分の道を歩め。", "D": "状況が誰かにとって不利である。"}},
334: {"nativeDefinition": "To understand the hidden or implied meaning.", "japaneseMeaning": "行間を読む、真意を汲み取る", "etymology": "read between the lines（行と行の間を読む）が言外の意味を理解することを表す。", "examples": {"B": "ビジネス交渉では通常カードを見せないから、行間を読む能力が重要。", "C": "冗談で言ったのに文字通り受け取って怒られた。もっと行間を読んでほしい。", "D": "隠されたメッセージを理解する。"}},
335: {"nativeDefinition": "To end someone's suffering, often by euthanasia.", "japaneseMeaning": "（苦痛から）解放してやる、安らかにさせる", "etymology": "put out of one's misery（苦しみから出す）が苦痛を終わらせることを表す。", "examples": {"B": "犬の安楽死は議論の的だけど、余命ない犬には選択肢としてあるべきだと思う。", "C": "検査結果は明日まで出ない。もう少し待って。", "D": "誰かの苦しみを終わらせる。"}},
336: {"nativeDefinition": "A situation where the same thing repeats monotonously.", "japaneseMeaning": "グラウンドホッグデー状態、同じことの繰り返し", "etymology": "映画『グラウンドホッグデー』から、同じ日が繰り返される状況を表す。", "examples": {"B": "最近やってることは仕事・食事・睡眠の繰り返し。グラウンドホッグデーみたいになってきた。", "C": "この動画を見るたびグラウンドホッグデー感じる。同じ内容をいろんな切り口で出してるだけ。", "D": "同じ日が繰り返される。"}},
337: {"nativeDefinition": "Frozen with fear or confusion; unable to react.", "japaneseMeaning": "（驚いて）固まる、頭が真っ白", "etymology": "deer in the headlights（ヘッドライトの前の鹿）が驚きで動けない状態を表す。", "examples": {"B": "面接官が予想外の質問をして、頭が真っ白になった。ヘッドライトの前の鹿みたいだった。", "C": "キャシー、プレゼン中にオーラの話をしたとき、ヘッドライトの前の鹿みたいな顔してた。", "D": "驚いて固まる。"}},
338: {"nativeDefinition": "A fundamental component or essential element.", "japaneseMeaning": "基本要素、構成要素", "etymology": "building block（積み木）が基礎的な構成要素を表す。", "examples": {"B": "有能さの重要な基本要素の一つは、多くの成功体験を積むこと。", "C": "成功の重要な構成要素は、戦略的思考と何があっても前進し続ける能力。", "D": "基本的な構成要素。"}},
339: {"nativeDefinition": "To punish someone as a warning to others.", "japaneseMeaning": "（人を）見せしめにする、懲らしめる", "etymology": "make an example of（例にする）が警告のための処罰を表す。", "examples": {"B": "マネージャーは今日ちょっと厳しかった。みんなの前で僕を叱って見せしめにした。", "C": "去年証券法違反で逮捕されたけど、強い証拠はなかった。検察は見せしめにしたかったんだと思う。", "D": "他の人への警告として誰かを罰する。"}},
340: {"nativeDefinition": "To remain popular or effective over a long period.", "japaneseMeaning": "時代に残る、長く愛される", "etymology": "stand the test of time（時の試練に耐える）が長年の評価を表す。", "examples": {"B": "スタンスミスは時代に残るアディダスの定番スニーカー。", "C": "マイケル・ジャクソンの音楽が時代に残ってるのはすごい。", "D": "長い間成功し続ける。"}},
341: {"nativeDefinition": "The more people involved, the better.", "japaneseMeaning": "多いほど楽しい、大勢の方がいい", "etymology": "the more the merrier（多いほど陽気）が人数が多い方が良いことを表す。", "examples": {"B": "友達も連れてきていいよ。多いほど楽しい。", "C": "このパーティー、人が多すぎない？まあ、多いほど楽しいか。", "D": "人が多いほど楽しい。"}},
342: {"nativeDefinition": "An unfair campaign to find and punish perceived wrongdoers.", "japaneseMeaning": "魔女狩り、不当な糾弾", "etymology": "witch hunt（魔女狩り）が根拠のない追及を表す。", "examples": {"B": "SNSの魔女狩りは人類の未来が心配になる。", "C": "中国政府が香港でやってることは、愛国心が足りない人への魔女狩りだと思う。", "D": "不当で非合理的な非難。"}},
343: {"nativeDefinition": "A person considered damaged or no longer valuable.", "japaneseMeaning": "使い物にならない人、傷物", "etymology": "damaged goods（傷物）が価値を失った人を比喩的に表す。", "examples": {"B": "4週間もプロジェクトにアサインされない。遠回しに使い物にならないって言ってるのかな。", "C": "成長し続けない人は、この厳しい職場ではすぐ傷物になる。", "D": "望まれないまたは不十分な人。"}},
344: {"nativeDefinition": "To deliberately provoke someone's anger.", "japaneseMeaning": "（人を）怒らせようとする、挑発する", "etymology": "get a rise out of（反応を引き出す）が意図的に怒らせることを表す。", "examples": {"B": "明らかにわざとじゃん。僕を怒らせようとしてるだけでしょ。ブロックする。", "C": "ごめん、冗談だったよ。怒らせようとしてたわけじゃない。", "D": "意図的に誰かを怒らせる。"}},
345: {"nativeDefinition": "To be honest and genuine.", "japaneseMeaning": "正直に言うと、本音を言うと", "etymology": "be real（本物である）が率直に話すことを表すスラング。", "examples": {"B": "ちょっと本音言っていい？実はお酒が好きじゃない。みんなが飲むから飲んでるだけ。", "C": "正直に言おう。多くの人は事実と意見を区別できない。だからフェイクニュースが広がる。", "D": "正直である。"}},
346: {"nativeDefinition": "Just in time; at the last possible moment.", "japaneseMeaning": "間一髪で、ぎりぎり間に合って", "etymology": "in the nick of time（時間の切れ目で）が間一髪を表す。", "examples": {"B": "閉店数分前にぎりぎり間に合った。", "C": "空港にぎりぎり間に合った。よかった。", "D": "ぎりぎり間に合って。"}},
347: {"nativeDefinition": "To have a grievance to settle with someone.", "japaneseMeaning": "（人に）恨みがある、雪辱を果たしたい", "etymology": "have a score to settle（決着をつける点数がある）が未解決の恨みを表す。", "examples": {"B": "ジョーカーとの決着をつけたかったんだ。ついにやった。", "C": "なんで僕の写真をみんなに送ったの？恨みでもあるの？", "D": "誰かに復讐したい。"}},
348: {"nativeDefinition": "Not knowing or understanding something.", "japaneseMeaning": "まったく気づいていない、わかっていない", "etymology": "none the wiser（少しも賢くない）が理解していないことを表す。", "examples": {"B": "AIは確かにパンドラの箱を開けたけど、多くの人はまったく気づいてない。いつか世界を支配するよ。", "C": "妹と友達のチャットを30分聞いてるけど、何の話かまったくわからない。", "D": "理解していない。"}},
349: {"nativeDefinition": "In a similar style or manner.", "japaneseMeaning": "同じ路線で、同様に", "etymology": "in the same vein（同じ血管で）が同様のスタイルを表す。", "examples": {"B": "『猫の恩返し』は他のジブリ作品とは違う路線だけど、楽しい映画。", "C": "子どもの頃コミック収集が好きだったし、同様にアニメにも夢中だった。", "D": "同様に。"}},
350: {"nativeDefinition": "In a situation too difficult to handle.", "japaneseMeaning": "手に負えない、能力を超えている", "etymology": "in over one's head（頭より深い）が対処できない状況を表す。", "examples": {"B": "2週間でマラソンに備えられると思ったけど、明らかに手に負えない。", "C": "新しい仕事は良いスタートだったけど、今は本当に手に負えない。何をすればいいかわからない。", "D": "能力を超えている。"}},
351: {"nativeDefinition": "When one thing happens, many similar things follow.", "japaneseMeaning": "泣きっ面に蜂、禍は重なる", "etymology": "when it rains, it pours（雨が降れば土砂降り）が不幸や幸運が重なることを表す。", "examples": {"B": "エアコンが壊れて、冷蔵庫のライトが消えて、今度は車が動かない。禍は重なるね。", "C": "昇給、新しい彼女、数週間後に休暇。幸運も重なるね。", "D": "良いことも悪いことも一気に起きる。"}},
352: {"nativeDefinition": "An unexpected twist or surprise.", "japaneseMeaning": "どんでん返し、プロットツイスト", "etymology": "plot twist（プロットのねじれ）が物語のどんでん返しを表す。", "examples": {"B": "宇宙人信じる？どんでん返し、僕は宇宙人だ。", "C": "明日2つの課題がある。どんでん返し、まだ一つも始めてない。", "D": "サプライズ！"}},
353: {"nativeDefinition": "To be the most extreme example; the ultimate.", "japaneseMeaning": "最高に〜だ、のぼり詰めた", "etymology": "take the cake（ケーキを取る）が最たる例を表す。", "examples": {"B": "ビルはいろんな変な決断してきたけど、ヘビをペットにするのは最高にやばい。", "C": "ケンのタトゥーは本当にすごい。面白いのは見たことあるけど、背中のピカチュウは最高。", "D": "最悪である。最高である。"}},
354: {"nativeDefinition": "Finally, but equally important.", "japaneseMeaning": "最後だが最も重要な", "etymology": "last but not least（最後だが最小ではない）が締めくくりの紹介を表す。", "examples": {"B": "最後だが最も重要な紹介です。本日のファシリテーター、ダグラス・カペル氏を。", "C": "最後に、今日参加してくれてありがとう。以上で終了です。次回お会いしましょう。お気をつけて！", "D": "最後だが同じくらい重要。"}},
355: {"nativeDefinition": "A highly competitive environment where people will do anything to succeed.", "japaneseMeaning": "弱肉強食の世界、しのぎを削る世界", "etymology": "dog-eat-dog（犬が犬を食う）が残酷な競争を表す。", "examples": {"B": "ビジネスは弱肉強食の世界。誰も信用できない。", "C": "弱肉強食の世界だとはわかってるけど、アダムは何があっても味方してくれると思う。長年の親友だから。", "D": "非常に競争の激しい環境。"}},
356: {"nativeDefinition": "Be quiet; stop talking.", "japaneseMeaning": "黙れ、うるさい", "etymology": "put a sock in it（靴下を入れる）が口を塞ぐ＝黙れのイギリス英語。", "examples": {"B": "フレッドに黙ってほしい。ずっと自慢話してる。", "C": "彼女に黙るよう頼める？甲高い声で耳が痛い。", "D": "静かにしろ。"}},
357: {"nativeDefinition": "Money is the most influential factor.", "japaneseMeaning": "金の力は偉大、金がものを言う", "etymology": "money talks（金が話す）が金の影響力を表す。", "examples": {"B": "ジョシュが別の会社に移ったことまだ悲しい？もう終わった話だよ。泣いても仕方ない。結局金がものを言う。", "C": "このアプリは広告が少なかった頃の方がよかった。悲しいけど、金がものを言う。", "D": "金は非常に影響力がある。"}},
358: {"nativeDefinition": "The process has already begun and cannot be stopped.", "japaneseMeaning": "すでに動き出している、歯車は回り始めた", "etymology": "the wheels are in motion（車輪が動いている）が始動済みを表す。", "examples": {"B": "本気だよ、次の選挙で大統領に立候補する。すでに動き出してる。", "C": "ヘレンは歯車が回り始めてからでないと計画を誰にも言わない。", "D": "プロセスはすでに始まっている。"}},
359: {"nativeDefinition": "To take the morally superior approach rather than retaliate.", "japaneseMeaning": "高潔な態度を取る、道徳的に正しい選択をする", "etymology": "take the high road（高い道を取る）が道徳的に優れた行動を表す。", "examples": {"B": "父はどんなに困難でも高潔な態度を取るよう教えてくれた。それが強い道徳観を育てた。", "C": "ヘイトはつきものだから無視して、いつも高潔な態度を取ろう。", "D": "道徳的に強い態度を取る。"}},
360: {"nativeDefinition": "To sell very quickly and in large quantities.", "japaneseMeaning": "飛ぶように売れる、大売れする", "etymology": "sell like hotcakes（ホットケーキのように売れる）が大ヒットを表す。", "examples": {"B": "僕の顔がプリントされたティッシュ、面白いよね。絶対大売れする。", "C": "お客はまだ少しずつ来てるけど、まだ朝早い。これらのピンズは大売れすると思う。すごくかわいいし。", "D": "素早く大量に売れる。"}},
361: {"nativeDefinition": "To reveal a lot about someone's character or feelings.", "japaneseMeaning": "（〜を）雄弁に示す、十分に物語る", "etymology": "speak volumes（多くを語る）が雄弁に示すことを表す。", "examples": {"B": "気候変動にグレーゾーンがあると思うこと自体が、科学を信じてないことを十分に物語ってる。", "C": "アレックスはローラに本気だと思う。彼女の前でのボディランゲージがすべてを物語ってる。", "D": "多くの情報を提供する。"}},
362: {"nativeDefinition": "To stress something very strongly.", "japaneseMeaning": "〜を強調しすぎることはない、いくら強調しても足りない", "etymology": "can't emphasize enough（十分に強調できない）が極度の強調を表す。", "examples": {"B": "英語が上手くなりたいなら、毎日英語に浸る必要がある。いくら強調しても足りない。", "C": "毎日少しずつ改善することにコミットする重要性を、いくら強調しても足りない。それが成功につながる。", "D": "強く信じている。"}},
363: {"nativeDefinition": "Something that is absolutely unacceptable.", "japaneseMeaning": "絶対ダメ、大タブー", "etymology": "big no-no（大きなダメ）が厳禁事項を表す。", "examples": {"B": "10時じゃなくて9時59分だよ。シフト終わる前に荷造りするのはここでは大タブー、いい？", "C": "許可なく他人の犬を撫でるのは大タブーだと思う？", "D": "受け入れられない行動。"}},
364: {"nativeDefinition": "To have good intentions even if the result is not ideal.", "japaneseMeaning": "悪気はない、善意で", "etymology": "mean well（良い意味で）が善意を表す。", "examples": {"B": "母は時々傷つくことを言うけど、いつも悪気はない。", "C": "ロイにランチ誘われるのやめてほしい。悪気はないのはわかるけど、一人でランチしたい。", "D": "善意を持っている。"}},
365: {"nativeDefinition": "Dangerous, risky, or frightening.", "japaneseMeaning": "（状況が）ハラハラする、危ない", "etymology": "hairy（毛深い）が口語で危険な状況を表す。", "examples": {"B": "飛行機の着陸はちょっとハラハラする。特に風が強いとき。", "C": "子どもの頃タランチュラでかなりハラハラする経験をした。だから彼女がペットにするの反対。", "D": "怖い。"}},
366: {"nativeDefinition": "To have no valid argument or support for one's position.", "japaneseMeaning": "（主張の）根拠がない、立場がない", "etymology": "not have a leg to stand on（立つ足がない）が根拠の欠如を表す。", "examples": {"B": "クライアントは口頭で著作権を譲渡したと同意したと言うけど、契約に書いてないから根拠がない。", "C": "テキスト履歴のスクリーンショットがあるなら、彼氏に主張の根拠はない。浮気してたのは明らかだ。", "D": "支持がない。"}},
367: {"nativeDefinition": "In a situation where no progress can be made.", "japaneseMeaning": "膠着状態の、行き詰まり", "etymology": "stalemate（ステイルメート）がチェス用語から交渉の行き詰まりを表す。", "examples": {"B": "60分経ってもまだ膠着状態だ。", "C": "彼女と今夜誰が夕食を作るかで膠着してる。結局Uber Eats頼むだろうね。", "D": "進展が不可能な状況にある。"}},
368: {"nativeDefinition": "To drive faster; hurry up.", "japaneseMeaning": "アクセル踏んで、急いで", "etymology": "step on it（それを踏む）がアクセルを踏む＝急げのスラング。", "examples": {"B": "ごめん、ちょっと遅れてるから、少しアクセル踏んでもらえる？", "C": "バスが遅すぎる。運転手がアクセル踏んでくれればいいのに。トイレに行きたい。", "D": "スピードアップ！"}},
369: {"nativeDefinition": "A hidden or selfish motive behind an action.", "japaneseMeaning": "裏の意図、下心", "etymology": "ulterior motive（奥の動機）が隠れた目的を表す。", "examples": {"B": "急にカップケーキをくれた。裏の意図が気になる。", "C": "中国が発展途上国を支援するのは下心があると批判する人もいるけど、西側も同じだと思う。", "D": "隠れた理由。"}},
370: {"nativeDefinition": "A failure; something that did not succeed.", "japaneseMeaning": "失敗、ダメなもの", "etymology": "bust（ bust）が失敗や破産を表すスラング。", "examples": {"B": "いくつかビジネスを持ってるから、一つ失敗しても大丈夫。", "C": "昨日野球カードを2パック買った。1パック目はダメだったけど、2パック目でショー・ヘイル・トニーのグラフカードが出た。かっこいい。", "D": "失敗。"}},
371: {"nativeDefinition": "To search secretly for private information.", "japaneseMeaning": "（こそこそ）探し回る、詮索する", "etymology": "snoop around（のぞき見る）が秘密を探ることを表す。", "examples": {"B": "パートナーのスマホを詮索するのはやめた方がいい。いいことは何も起きない。", "C": "好きな人のインスタをこそこそ見てたら、うっかりいいねしそうになった。怖かった！", "D": "秘密をこっそり探す。"}},
372: {"nativeDefinition": "In one's imagination; as one pictures it mentally.", "japaneseMeaning": "心の中では、想像の中で", "etymology": "in one's mind's eye（心の目で）が想像上の映像を表す。", "examples": {"B": "ピアノを弾くのは心の中ではかっこよく見えたけど、上手くなるにはどれだけ練習が必要かわかってなかった。", "C": "実際に会ったことはないけど、心の中では完璧に姿が浮かぶ。", "D": "誰かの想像の中で。"}},
373: {"nativeDefinition": "To repair something temporarily or hastily.", "japaneseMeaning": "（とりあえず）修理する、応急処置する", "etymology": "patch up（継ぎ接ぎする）が一時的な修理を表す。", "examples": {"B": "今板挟みなんだ。車を数千ドルかけて応急修理するか、もう少し出して新しいのを買うか。", "C": "医者に行った方がいい。あんな傷は応急処置じゃ無理。", "D": "一時的に修理する。"}},
374: {"nativeDefinition": "To make someone feel less guilty.", "japaneseMeaning": "（良心を）少し楽にする", "etymology": "ease one's conscience（良心を和らげる）が罪悪感を軽減することを表す。", "examples": {"B": "海に落ちる一滴かもしれないけど、再利用カップで環境のために少しでもやりたい。良心も少し楽になる。", "C": "夕食にチーズバーガー2つと大フライドポテト食べたから、罪悪感を和らげるためにグリーンジュース1杯飲んだ。", "D": "誰かの罪悪感を軽くする。"}},
375: {"nativeDefinition": "In the modern era; nowadays.", "japaneseMeaning": "現代では、今の時代に", "etymology": "in this day and age（この日と時代に）が現代社会を表す。", "examples": {"B": "政府は全員に無料スマホを配るべきだと思う。現代ではスマホなしでは生きられない。", "C": "大臣がUSBが何かわからないと言って自分の首を絞めた。現代でそんなことある？狂ってるよ。", "D": "現在において。"}},
376: {"nativeDefinition": "To leave a job, team, or organization.", "japaneseMeaning": "（会社などを）去る、退職する", "etymology": "head for the exit door（出口ドアに向かう）が去ることを表す。", "examples": {"B": "え、ロナウドが去るの？チームにとって大きな損失だ。", "C": "昼休みにジャックがLinkedInで求人を見てた。退職のサインかも。", "D": "去る。"}},
377: {"nativeDefinition": "A situation where one person's gain is another's loss.", "japaneseMeaning": "ゼロサムゲーム、一方の得は他方の損", "etymology": "zero-sum game（ゼロ和ゲーム）がゲーム理論用語から競争社会を表す。", "examples": {"B": "人生はゼロサムゲームじゃない。他人の成功を妬むのはやめよう。", "C": "ビジネスはゼロサムゲームだと思う人もいるけど、僕はそう思わない。協力してウィンウィンを作る方法はたくさんある。", "D": "一方の得が他方の損となるもの。"}},
378: {"nativeDefinition": "A wise, mature person who seems older than their years.", "japaneseMeaning": "老成した人、古風な魂", "etymology": "old soul（古い魂）が年齢以上に成熟した人を表す。", "examples": {"B": "物質的じゃなく、シンプルな生活を好んで一人の時間を楽しむ。本当に老成した人だ。", "C": "テキストより電話が好き。たぶん僕は老成した人間なんだ。", "D": "とても成熟した人、古風な人。"}},
379: {"nativeDefinition": "A curated collection showing only the best moments.", "japaneseMeaning": "ハイライトリール、良いところだけ", "etymology": "highlight reel（ハイライト映像）が編集された良い部分だけを表す。", "examples": {"B": "みんなのインスタ見ると人生完璧に見えるけど、良いところだけのハイライトリールなんだ。", "C": "僕のブログは食べに行った場所のハイライトリール。いつも高級料理食べてるわけじゃない。", "D": "最高の部分。"}},
380: {"nativeDefinition": "To cause public controversy or excitement.", "japaneseMeaning": "騒ぎを起こす、物議を醸す", "etymology": "cause a stir（かき混ぜる）が世間を騒がせることを表す。", "examples": {"B": "バンクシーが140万ドルで売れた絵を破り捨てて物議を醸した。", "C": "ホームレスの人へのコメントを聞いたとき、騒ぎが起きるとわかってた。", "D": "ドラマや騒動を起こす。"}},
381: {"nativeDefinition": "To appear unexpectedly, often in large numbers.", "japaneseMeaning": "（突然）現れる、ぞろぞろ出てくる", "etymology": "come out of the woodwork（木目から出てくる）が思いがけず現れることを表す。", "examples": {"B": "何か新しいことを始めると、人はぞろぞろ出てきて「本当にやるの？」って言う。気にしないで。", "C": "宝くじ当たった途端、女の子がぞろぞろ出てきたの面白いね。", "D": "突然現れる。"}},
382: {"nativeDefinition": "Both parties must participate equally for something to work.", "japaneseMeaning": "二人でなければ踊れない、双方の努力が必要", "etymology": "it takes two to tango（タンゴには二人必要）が双方の関与を表す。", "examples": {"B": "どんな関係でも二人でなければ成り立たない。どれだけ愛してても、相手も愛してくれないとダメ。", "C": "契約を延長したいけど、二人でなければならない。交渉がうまくいくといいな。", "D": "両方が同等に関与する必要がある。"}},
383: {"nativeDefinition": "To promote or advocate for something enthusiastically.", "japaneseMeaning": "（〜を）力強く訴える、盛んに宣伝する", "etymology": "bang the drum（太鼓を叩く）が熱心に訴えることを表す。", "examples": {"B": "在宅勤務を何年も力強く訴えてきた。ますます許されるようになって嬉しい。", "C": "この映画を何年も宣伝してきた。おっと、噂をすれば影。今トレーラーのリンク送ってきた。", "D": "熱心に支持する。"}},
384: {"nativeDefinition": "To hold court; to be the center of attention while speaking.", "japaneseMeaning": "（人々の）中心にいて話す、饒舌に語る", "etymology": "hold court（宮廷を開く）が王のように人々の注目を集めることを表す。", "examples": {"B": "あそこで人々の中心になって話してる男は誰？有名人？", "C": "父がまた庭で人々の中心になって話してる。みんな話に夢中になってるといいな。", "D": "注目を集めて面白く話す。"}},
385: {"nativeDefinition": "To have been better in the past; to show signs of decline.", "japaneseMeaning": "昔はもっと良かった、老朽化した", "etymology": "seen better days（もっと良い日を見た）が過去の栄光を表す。", "examples": {"B": "日本経済は確かに昔はもっと良かったけど、ほとんどの国と比べればまだいいと思う。", "C": "このジーンズはもうボロボロだ。新しいの買う時期かも。", "D": "以前はもっと良かった、悪くなったか古くなった。"}},
386: {"nativeDefinition": "Perfectly suited for a particular purpose or person.", "japaneseMeaning": "（〜に）ぴったりの、オーダーメイドの", "etymology": "tailor-made（仕立てられた）が完璧に合うことを表す。", "examples": {"B": "彼はすごく背が高くて強い。バスケをするために生まれたみたい。", "C": "この水泳クラスは初心者向けに作られてる。", "D": "何かに完璧に合っている。"}},
387: {"nativeDefinition": "To lose in a competition or conflict.", "japaneseMeaning": "負ける、敗れる", "etymology": "come off second best（二番目に終わる）が負けることを表す。", "examples": {"B": "うちのチームはまた負けたけど、すごく接戦だった。前回はボロボロにされたから、確実に上達してる。", "C": "昨日食べ競争に参加した。友達に煽られて。残念ながら負けた。", "D": "負ける。"}},
388: {"nativeDefinition": "To obstruct or hinder someone.", "japaneseMeaning": "（人の）邪魔をする、足を引っ張る", "etymology": "get in one's way（道に入る）が妨害することを表す。", "examples": {"B": "妻が料理してるときはキッチンに入らないようにしてる。邪魔になるだけだから。", "C": "会議に一緒に行っていい？邪魔はしないから。", "D": "誰かの邪魔をする。"}},
389: {"nativeDefinition": "Including all flaws and imperfections; completely.", "japaneseMeaning": "欠点も含めて、ありのままで", "etymology": "warts and all（イボも全部）が欠点も含めた全体を表す。", "examples": {"B": "幸せになりたいなら、まず自分を欠点も含めて受け入れなきゃ。", "C": "昨夜のデート、すごく意気投合した。欠点も含めて全部共有し合った。", "D": "すべてのネガティブなものを含めて。"}},
390: {"nativeDefinition": "To act boldly without worrying about risks.", "japaneseMeaning": "思い切ってやる、リスクを恐れない", "etymology": "throw caution to the wind（注意を風に投げる）が大胆に行動することを表す。", "examples": {"B": "思い切って仕事を辞めたい。毎日情熱のないことをするのがしっくりこない。", "C": "ソフトローは食べたことないけど、強引に勧められてるし、思い切って食べてみる。", "D": "大胆に行動する。"}},
391: {"nativeDefinition": "To prevent something from succeeding or progressing.", "japaneseMeaning": "（計画などを）脱線させる、台無しにする", "etymology": "derail（脱線させる）が計画の妨害を表す。", "examples": {"B": "多くの政治家がレッドヘリングで会話を脱線させるのが本当に嫌い。", "C": "この電話で週末の計画が完全に脱線した。", "D": "何かの成功や進展を妨げる。"}},
392: {"nativeDefinition": "To be much better than someone at something.", "japaneseMeaning": "（人を）圧倒する、ずば抜けている", "etymology": "run circles around（周りを走り回る）が相手をはるかに上回ることを表す。", "examples": {"B": "内装の面ではメルセデス・ベンツが他社を圧倒してる。", "C": "料理に関しては父が喜んで全部やる。僕をずば抜けてるから。僕はいつも皿洗いするけど。", "D": "誰かよりずっと優れている。"}},
393: {"nativeDefinition": "To try something cautiously to see if it will work.", "japaneseMeaning": "（様子を）見る、試しにやってみる", "etymology": "test the waters（水を試す）が慎重に試すことを表す。", "examples": {"B": "元カノと戻りたい？メッセージ送って様子見しよう。返事なければ次に進め。", "C": "このカードをeBayで1200ドルで出品してみてる。様子見。そんな大金払う人いないと思うけど。", "D": "成功の可能性を調べる。"}},
394: {"nativeDefinition": "To enjoy something greatly, often at someone's expense.", "japaneseMeaning": "（〜を）大いに楽しむ、いじり倒す", "etymology": "have a field day（一日中大騒ぎ）が存分に楽しむことを表す。", "examples": {"B": "この男の仕草がすごく面白い。ジェフのクリエイターがいじり倒すだろうね。", "C": "大統領はすぐにツイートの誤字を直したけど、SNSはもういじり倒してる。", "D": "何かからたくさん楽しむ。"}},
395: {"nativeDefinition": "Someone is not naive or easily fooled.", "japaneseMeaning": "騙されないよ、バカじゃない", "etymology": "wasn't born yesterday（昨日生まれたわけじゃない）が騙されないことを表す。", "examples": {"B": "説明が辻褄合わない。日本に年利30%の貯蓄口座があるなんて信じると思った？騙されないよ。", "C": "おい、騙されないよ。宿題を犬が食べたなんて本気で信じるの？", "D": "そんなにバカじゃない。"}},
396: {"nativeDefinition": "Disparaging something one cannot have out of bitterness.", "japaneseMeaning": "酸っぱいブドウ、負け惜しみ", "etymology": "イソップ寓話の酸っぱいブドウ（sour grapes）から、負け惜しみを表す。", "examples": {"B": "ネガティブなコメントで成功を台無しにしないで。ただの負け惜しみだよ。", "C": "クリスは昇進しなくて「どうせ昇進なんて欲しくなかった、責任ばかりで給料も少ない」って。負け惜しみでしょ？", "D": "妬み。"}},
397: {"nativeDefinition": "Demanding a lot of attention and effort to maintain.", "japaneseMeaning": "手のかかる、わがままな", "etymology": "high-maintenance（メンテナンスが多い）が手間のかかる人を表す。", "examples": {"B": "価格競争すべきじゃない。高い価格は手のかかる顧客を引き付ける。", "C": "彼女は手のかかるし満足させにくいから、追うのやめた。", "D": "要求が多い。"}},
398: {"nativeDefinition": "Out of sight, out of mind; forgetting what is not visible.", "japaneseMeaning": "去る者は日々に疎し、眼の外にあるものは心にもない", "etymology": "out of sight, out of mind（見えなければ心にもない）が見えないものを忘れることを表す。", "examples": {"B": "うざい人はブロックする。眼の外、心外。", "C": "在宅勤務は大抵いいけど、昇進がずっと難しくなる。眼の外、心外だから。", "D": "見えないと無視しやすい。"}},
399: {"nativeDefinition": "To be a common characteristic in a family.", "japaneseMeaning": "家系に受け継がれる、血筋", "etymology": "run in the family（家族の中を走る）が遺伝的特徴を表す。", "examples": {"B": "子どもたちも背が高いね。家系に受け継がれてるみたい。", "C": "よく考えたら、父も祖父も声が低かった。たぶん家系に受け継がれてる。", "D": "遺伝的なものである。"}},
400: {"nativeDefinition": "To bully or repeatedly criticize someone unfairly.", "japaneseMeaning": "（人を）いじめる、当たり散らす", "etymology": "pick on（選んで攻撃する）が特定の人を狙って嫌がらせすることを表す。", "examples": {"B": "先生は僕が聞いてないとわかってるのに、わざと質問してくる。いじめてる。", "C": "ジョンは冗談だと言うけど、明らかにエマをいじめてる。", "D": "いじめの標的にする。"}},
}
